// Simulation function
void simulateElevator(int numElevators, int floors, int residents, int tripsPerHour) {
    // Initialize elevators
    vector<Elevator> elevators(numElevators);
    for (int i = 0; i < numElevators; i++) {
        elevators[i] = Elevator(floors / 2, 4);
    }

    // Simulate residents
    random_device rd;
    mt19937 gen(rd());
    uniform_int_distribution<> dist(1, floors);
    for (int i = 0; i < residents; i++) {
        int floor = dist(gen);
        Resident resident(floor);
        resident.isWaiting = true;
        cout << "Resident " << i + 1 << " is waiting on floor " << resident.floor << endl;
        // Simulate waiting time
        this_thread::sleep_for(chrono::seconds(1));
        resident.isWaiting = false;
    }

    // Simulate elevator trips
    for (int i = 0; i < tripsPerHour; i++) {
        // Randomly choose an elevator
        int elevatorIndex = rand() % numElevators;
        // Simulate elevator movement
        elevators[elevatorIndex].moveUp();
        // Simulate waiting time
        this_thread::sleep_for(chrono::seconds(1));
        elevators[elevatorIndex].stop();
    }
}

