import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class ParallelTSVReader {

    public static void main(String[] args) {
        String filePath = "input.tsv"; // Replace with your TSV file path
        int numThreads = Runtime.getRuntime().availableProcessors(); // Use available processors

        ExecutorService executor = Executors.newFixedThreadPool(numThreads);

        try (BufferedReader reader = new BufferedReader(new FileReader(filePath))) {
            String line;
            List<String[]> data = new ArrayList<>();
            while ((line = reader.readLine()) != null) {
                String[] row = line.split(",");
                data.add(row);
            }

            // Process each row in parallel
            for (int i = 0; i < numThreads; i++) {
                executor.execute(new ProcessRowTask(data, i));
            }
            executor.shutdown();
            try {
                executor.awaitTermination(1, TimeUnit.HOURS);
            } catch (InterruptedException e) {
                System.err.println("Tasks interrupted: " + e.getMessage());
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }

    static class ProcessRowTask implements Runnable {
        private List<String[]> data;
        private int threadId;

        public ProcessRowTask(List<String[]> data, int threadId) {
            this.data = data;
            this.threadId = threadId;
        }

        @Override
        public void run() {
            for (String[] row : data) {
                // Process each row here
                System.out.println(String.format("Row %d: %s", threadId, row));
            }
        }
    }
}
```

