interface Order {
  id: string;
  customer: Customer;
  status: Status;
  price: Price;
  timeline: Timeline;
}

const initialState: Order[] = [
  {
    id: '1',
    customer: { id: '1', name: 'John Doe' },
    status: { value: 'Pending', label: 'Pending' },
    price: { value: 100, currency: 'USD' },
    timeline: {
      events: [
        { id: '1', timestamp: '2023-03-01T10:00:00Z', type: 'Created', details: 'Order created' },
        { id: '2', timestamp: '2023-03-02T12:00:00Z', type: 'Shipped', details: 'Order shipped' },
      ],
    },
  },
];

const orderSlice = createSlice({
  name: 'orderSlice',
  initialState,
  reducers: {
    updateTimeline: (state, action: PayloadAction<Order>) => {
      const updatedOrder = cloneDeep(state.find((order) => order.id === action.payload.id));
      updatedOrder.timeline.events.push(action.payload.timeline.events[0]);
      return state.map((order) =>
        order.id === action.payload.id ? updatedOrder : order
      );
    },
  },
});

export const { updateTimeline } = orderSlice.actions;
export default orderSlice.reducer;
