```csharp
public class FixedSizeConcurrentQueue<T>
{
    private readonly int _capacity;
    private readonly Queue<Task<T>> _queue;
    private readonly SemaphoreSlim _semaphore;

    public FixedSizeConcurrentQueue(int capacity)
    {
        _capacity = capacity;
        _queue = new Queue<Task<T>>();
        _semaphore = new SemaphoreSlim(1);
    }

    public async Task Enqueue(Task<T> task)
    {
        await _semaphore.WaitAsync();
        _queue.Enqueue(task);
        await _semaphore.ReleaseAsync();
    }

    public async Task<T> Dequeue()
    {
        await _semaphore.WaitAsync();
        if (_queue.Count == 0)
        {
            await _semaphore.ReleaseAsync();
            throw new InvalidOperationException("Queue is empty.");
        }
        var task = _queue.Dequeue();
        await _semaphore.ReleaseAsync();
        return await task;
    }
}
```

