    matrix = QMatrix();
    painter = new QPainter(image);
    isZooming = false;
    zoomFactor = 1.0;
    startPoint = QPoint(0, 0);
    currentPoint = QPoint(0, 0);
}

MatrixBitmapWidget::~MatrixBitmapWidget()
{
    delete image;
    delete painter;
}

void MatrixBitmapWidget::paintEvent(QPaintEvent *event)
{
    QPainter painter(this);
    painter.drawImage(0, 0, *image);
}

void MatrixBitmapWidget::mousePressEvent(QMouseEvent *event)
{
    startPoint = event->pos();
    isZooming = true;
}

void MatrixBitmapWidget::mouseMoveEvent(QMouseEvent *event)
{
    if (isZooming) {
        currentPoint = event->pos();
        double deltaX = currentPoint.x() - startPoint.x();
        double deltaY = currentPoint.y() - startPoint.y();
        zoomFactor = 1.0 + (deltaX / 100) * 0.1;
        matrix.translate(deltaX, deltaY);
    }
}

