using StackExchange.Redis;

public class RedisCacheWriter
{
    private readonly string _redisConnectionString;
    private readonly IDatabase _redisDatabase;

    public RedisCacheWriter(string redisConnectionString)
    {
        _redisConnectionString = redisConnectionString;
        _redisDatabase = ConnectionMultiplexer.Connect(_redisConnectionString).GetDatabase(0);
    }

    public async Task WriteModelAsync(string key, object model, CancellationToken cancellationToken = default)
    {
        // Lock the model for exclusive access
        using (var lockToken = _redisDatabase.Lock(key, TimeSpan.FromHours(24)))
        {
            try
            {
                await _redisDatabase.SetAsync(key, model, TimeSpan.FromDays(1));
                Console.WriteLine($"Model written to cache with key: {key}");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error writing model to cache: {ex.Message}");
            }
        }
    }
}
```

